define i1 @simplify_fcmp_ord_fmul_caller(double nofpclass(nan inf zero) %i0, double nofpclass(nan inf zero) %i1) {
  %call = call i1 @simplify_fcmp_ord_fmul_callee(double %i0, double %i1)
  ret i1 %call
}

declare hidden i1 @simplify_fcmp_ord_fmul_callee(double, double)

define hidden i1 @simplify_fcmp_ord_frem_callee(double %a, double %b) {
  %sub.double.sub = frem double %a, %b
  %cmp = fcmp ord double %sub.double.sub, 0.000000e+00
  ret i1 %cmp
}

define i1 @issue63316_commute(i64 %arg) {
  %sitofp = sitofp i64 %arg to float
  %fmul = fmul float 0x7FF0000000000000, %sitofp
  %fcmp = fcmp uno float %fmul, 0.000000e+00
  ret i1 %fcmp
}

